import React, { useState, useEffect } from 'react';
import { supabase } from './supabase';
import Login from './components/Login';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import Pedidos from './components/Pedidos';
import Productos from './components/Productos';
import Clientes from './components/Clientes';
import Reportes from './components/Reportes';

export default function App() {
  const [session, setSession] = useState(null);
  const [cargando, setCargando] = useState(true);
  const [pagina, setPagina] = useState('dashboard');
  const [negocio, setNegocio] = useState(null);
  const [pedidos, setPedidos] = useState([]);
  const [productos, setProductos] = useState([]);
  const [clientes, setClientes] = useState([]);
  const [notif, setNotif] = useState(null);

  const pedidosNuevos = pedidos.filter(p => p.estado === 'nuevo').length;

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setCargando(false);
    });
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (!session) { setNegocio(null); setPedidos([]); setProductos([]); setClientes([]); }
    });
    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    if (!session) return;
    const cargarNegocio = async () => {
      const { data } = await supabase.from('negocios').select('*').eq('user_id', session.user.id).single();
      if (data) {
        setNegocio(data);
        cargarPedidos(data.id);
        cargarProductos(data.id);
        cargarClientes(data.id);
        // Refrescar pedidos cada 15 segundos
        const intervalo = setInterval(() => cargarPedidos(data.id), 15000);
        return () => clearInterval(intervalo);
      }
    };
    cargarNegocio();
  }, [session]);

  const cargarPedidos = async (negocioId) => {
    const { data } = await supabase.from('pedidos').select('*').eq('negocio_id', negocioId).order('created_at', { ascending: false });
    if (data) {
      setPedidos(prev => {
        const hayNuevo = data.length > prev.length;
        if (hayNuevo && prev.length > 0) {
          setNotif(`🔔 Nuevo pedido de ${data[0].cliente_nombre}`);
          setTimeout(() => setNotif(null), 5000);
        }
        return data;
      });
    }
  };

  const cargarProductos = async (negocioId) => {
    const { data } = await supabase.from('productos').select('*').eq('negocio_id', negocioId).order('created_at', { ascending: true });
    if (data) setProductos(data);
  };

  const cargarClientes = async (negocioId) => {
    const { data } = await supabase.from('pedidos').select('cliente_nombre, cliente_telefono, cliente_direccion, total, created_at').eq('negocio_id', negocioId);
    if (data) {
      const mapa = {};
      data.forEach(p => {
        const key = p.cliente_telefono || p.cliente_nombre;
        if (!mapa[key]) mapa[key] = { nombre: p.cliente_nombre, telefono: p.cliente_telefono, direccion: p.cliente_direccion, pedidos: 0, gasto: 0, ultimo: p.created_at };
        mapa[key].pedidos += 1;
        mapa[key].gasto += Number(p.total) || 0;
        if (p.created_at > mapa[key].ultimo) mapa[key].ultimo = p.created_at;
      });
      setClientes(Object.values(mapa));
    }
  };

  const cambiarEstado = async (id, nuevoEstado) => {
    setPedidos(prev => prev.map(p => p.id === id ? { ...p, estado: nuevoEstado } : p));
    await supabase.from('pedidos').update({ estado: nuevoEstado }).eq('id', id);
  };

  const agregarProducto = async (prod) => {
    const { data } = await supabase.from('productos').insert({ ...prod, negocio_id: negocio.id }).select().single();
    if (data) setProductos(prev => [...prev, data]);
  };

  const toggleProducto = async (id, activo) => {
    setProductos(prev => prev.map(p => p.id === id ? { ...p, activo } : p));
    await supabase.from('productos').update({ activo }).eq('id', id);
  };

  const cerrarSesion = () => supabase.auth.signOut();

  if (cargando) {
    return (
      <div style={{ minHeight:'100vh', display:'flex', alignItems:'center', justifyContent:'center', background:'#F1F5F9' }}>
        <div style={{ textAlign:'center' }}>
          <div style={{ fontSize:32, marginBottom:8 }}>🛍</div>
          <div style={{ fontSize:14, color:'#64748B' }}>Cargando PedidosFácil...</div>
        </div>
      </div>
    );
  }

  if (!session) return <Login />;

  return (
    <div style={{ display:'flex', minHeight:'100vh' }}>
      <Sidebar pagina={pagina} setPagina={setPagina} pedidosNuevos={pedidosNuevos} negocio={negocio} onCerrarSesion={cerrarSesion} />
      <main style={{ flex:1, overflowY:'auto', background:'#F1F5F9' }}>
        {pagina === 'dashboard' && <Dashboard pedidos={pedidos} productos={productos} setPagina={setPagina} negocio={negocio} />}
        {pagina === 'pedidos'   && <Pedidos pedidos={pedidos} onCambiarEstado={cambiarEstado} />}
        {pagina === 'productos' && <Productos productos={productos} onAgregarProducto={agregarProducto} onToggleProducto={toggleProducto} />}
        {pagina === 'clientes'  && <Clientes clientes={clientes} />}
        {pagina === 'reportes'  && <Reportes pedidos={pedidos} productos={productos} />}
        {pagina === 'config'    && (
          <div style={{ padding:'1.5rem' }}>
            <h1 style={{ fontSize:20, fontWeight:700, marginBottom:'1rem' }}>Configuración</h1>
            <div style={{ background:'#fff', borderRadius:12, padding:'1.25rem', maxWidth:480 }}>
              <div style={{ fontWeight:600, marginBottom:'1rem' }}>Datos del negocio</div>
              <p style={{ fontSize:14, color:'#64748B', marginBottom:6 }}>Negocio: <strong>{negocio?.nombre}</strong></p>
              <p style={{ fontSize:14, color:'#64748B', marginBottom:6 }}>Tipo: <strong>{negocio?.tipo}</strong></p>
              <p style={{ fontSize:14, color:'#64748B', marginBottom:'1rem' }}>Email: <strong>{session.user.email}</strong></p>
              <div style={{ background:'#F0FDF4', borderRadius:10, padding:'1rem', marginBottom:'1.25rem' }}>
                <div style={{ fontSize:13, fontWeight:600, color:'#15803D', marginBottom:6 }}>🔗 Link para tus clientes:</div>
                <div style={{ fontSize:12, color:'#166534', wordBreak:'break-all', fontFamily:'monospace' }}>
                  http://localhost:3001?negocio={negocio?.id}
                </div>
              </div>
              <button onClick={cerrarSesion}
                style={{ padding:'8px 20px', borderRadius:8, border:'1px solid #FCA5A5', background:'#FEF2F2', color:'#DC2626', fontWeight:600, cursor:'pointer', fontSize:14 }}>
                Cerrar sesión
              </button>
            </div>
          </div>
        )}
      </main>
      {notif && (
        <div style={{ position:'fixed', top:20, right:20, background:'#1E293B', color:'#fff', padding:'14px 20px', borderRadius:12, fontSize:14, fontWeight:500, zIndex:9999, boxShadow:'0 4px 20px rgba(0,0,0,0.3)' }}>
          {notif}
        </div>
      )}
    </div>
  );
}
